define(["core/ajax","core/notification"],function(Ajax,Notification){function escapeHtml(s){var d=document.createElement("div");d.textContent=s||"";return d.innerHTML}function loadClasses(envId){Ajax.call([{methodname:"local_rangeos_list_scenario_classes",args:{envid:envId}}])[0].then(function(r){var sel=document.getElementById("scenario-class-filter");if(!sel)return;r.classes.forEach(function(c){var o=document.createElement("option");o.value=c.name;o.textContent=c.name;sel.appendChild(o)})}).catch(Notification.exception)}function searchScenarios(envId,search,classFilter,container,selected,onSelect){var rd=container.querySelector("#scenario-results");rd.innerHTML="<div class=\"p-2 text-muted\">Loading...</div>";Ajax.call([{methodname:"local_rangeos_list_scenarios",args:{envid:envId,search:search,classfilter:classFilter,page:0,pagesize:50}}])[0].then(function(r){rd.innerHTML="";if(!r.scenarios.length){rd.innerHTML="<div class=\"p-2 text-muted\">No scenarios found.</div>";return}r.scenarios.forEach(function(sc){var isSel=selected.some(function(s){return s.id===sc.id});var item=document.createElement("a");item.href="#";item.className="list-group-item list-group-item-action";if(isSel)item.classList.add("active");item.innerHTML="<strong>"+escapeHtml(sc.name)+"</strong> <small class=\"text-muted\">"+escapeHtml(sc["class"])+"</small>";item.addEventListener("click",function(e){e.preventDefault();var idx=-1;for(var i=0;i<selected.length;i++){if(selected[i].id===sc.id){idx=i;break}}if(idx>=0){selected.splice(idx,1);item.classList.remove("active")}else{selected.push({id:sc.id,name:sc.name});item.classList.add("active")}updateDisplay(container,selected);var ta=document.getElementById("mapping-scenarios");if(ta)ta.value=JSON.stringify(selected,null,2);if(onSelect)onSelect(selected)});rd.appendChild(item)})}).catch(Notification.exception)}function updateDisplay(container,selected){var d=container.querySelector("#scenario-selected");if(!selected.length){d.innerHTML="";return}d.innerHTML="<strong>Selected:</strong> "+selected.map(function(s){return"<span class=\"badge badge-primary mr-1\">"+escapeHtml(s.name)+"</span>"}).join("")}return{init:function(containerSelector,envId,onSelect){var container=document.querySelector(containerSelector);if(!container)return;container.innerHTML="<div class=\"scenario-picker\"><div class=\"input-group mb-2\"><input type=\"text\" class=\"form-control\" id=\"scenario-search\" placeholder=\"Search scenarios...\"><select class=\"custom-select\" id=\"scenario-class-filter\" style=\"max-width:200px\"><option value=\"\">All classes</option></select><div class=\"input-group-append\"><button class=\"btn btn-outline-secondary\" id=\"scenario-search-btn\" type=\"button\">Search</button></div></div><div id=\"scenario-results\" class=\"list-group mb-2\" style=\"max-height:300px;overflow-y:auto\"></div><div id=\"scenario-selected\" class=\"mb-2\"></div></div>";var selected=[];loadClasses(envId);var searchBtn=container.querySelector("#scenario-search-btn");var searchInput=container.querySelector("#scenario-search");var doSearch=function(){searchScenarios(envId,searchInput.value.trim(),container.querySelector("#scenario-class-filter").value,container,selected,onSelect)};searchBtn.addEventListener("click",doSearch);searchInput.addEventListener("keydown",function(e){if(e.key==="Enter"){e.preventDefault();doSearch()}})}};});
